eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   faqData: () => (/* binding */ faqData)\n/* harmony export */ });\nconst faqData = {\n    'Guardias de Seguridad': [\n        {\n            question: '¿Qué funciones cumplen los guardias de Gard Security?',\n            answer: 'Nuestros guardias están capacitados para proteger personas, instalaciones y activos, realizando controles de acceso, rondas preventivas, disuasión de amenazas y primeros auxilios.'\n        },\n        {\n            question: '¿Los guardias cuentan con certificación OS10?',\n            answer: 'Sí, todos nuestros guardias poseen OS10 al día y pasan por procesos de capacitación continua adaptados a cada industria.'\n        },\n        {\n            question: '¿Qué tipo de industrias cubren los servicios de guardias?',\n            answer: 'Prestamos servicios a minería, retail, salud, educación, eventos, instituciones públicas y privadas, y más.'\n        },\n        {\n            question: '¿Cómo seleccionan al personal de seguridad?',\n            answer: 'Nuestro proceso incluye revisión de antecedentes, entrevistas psicolaborales y entrenamiento específico por rubro.'\n        },\n        {\n            question: '¿Puedo solicitar guardias para un evento puntual?',\n            answer: 'Sí, ofrecemos servicios de guardias temporales para eventos corporativos, sociales, deportivos y masivos.'\n        }\n    ],\n    'Monitoreo y CCTV': [\n        {\n            question: '¿Qué incluye el servicio de monitoreo remoto?',\n            answer: 'Supervisión en tiempo real desde nuestra Central de Monitoreo con videoverificación, rondas virtuales y protocolos personalizados.'\n        },\n        {\n            question: '¿Qué ventajas ofrece el monitoreo con inteligencia artificial?',\n            answer: 'La IA permite detectar intrusiones, comportamientos sospechosos y generar alertas automáticas en segundos.'\n        },\n        {\n            question: '¿Puedo integrar mis cámaras actuales al sistema de monitoreo?',\n            answer: 'Sí, evaluamos la infraestructura existente para integrarla o mejorarla sin costos innecesarios.'\n        },\n        {\n            question: '¿Qué pasa si se detecta una intrusión?',\n            answer: 'Se activa el protocolo de emergencia, contactando a las autoridades y notificando al cliente en tiempo real.'\n        },\n        {\n            question: '¿Qué es una ronda virtual?',\n            answer: 'Es una inspección programada de tus cámaras, realizada por nuestro equipo sin necesidad de un guardia físico en el lugar.'\n        }\n    ],\n    'Drones de Seguridad': [\n        {\n            question: '¿Cómo funcionan los drones de seguridad?',\n            answer: 'Realizan rondas aéreas programadas o por demanda, con cámaras HD, visión nocturna y análisis por IA.'\n        },\n        {\n            question: '¿Qué ventajas tienen frente a los guardias tradicionales?',\n            answer: 'Cobertura más amplia, sin fatiga, con detección temprana de riesgos y operación en zonas de difícil acceso.'\n        },\n        {\n            question: '¿Los drones operan de noche?',\n            answer: 'Sí, gracias a visión infrarroja y sensores térmicos, los drones pueden vigilar eficientemente en condiciones nocturnas.'\n        },\n        {\n            question: '¿Puedo combinar drones con guardias físicos?',\n            answer: 'Absolutamente. Diseñamos soluciones híbridas para maximizar la eficiencia y cobertura.'\n        },\n        {\n            question: '¿Es legal usar drones para seguridad en empresas?',\n            answer: 'Sí, cumplimos con la normativa DGAC y diseñamos cada operación según la regulación vigente.'\n        }\n    ],\n    'Tecnología e Innovación': [\n        {\n            question: '¿Qué tecnologías integran sus servicios de seguridad?',\n            answer: 'Usamos IA, análisis de video, reconocimiento facial, sistemas biométricos, apps móviles y más.'\n        },\n        {\n            question: '¿Puedo controlar la seguridad desde mi celular?',\n            answer: 'Sí, ofrecemos apps personalizadas para que visualices cámaras, recibas alertas y actives protocolos desde tu smartphone.'\n        },\n        {\n            question: '¿Qué diferencia a Gard Security en tecnología?',\n            answer: 'Somos pioneros en integrar drones, inteligencia artificial y automatización con servicios de seguridad humana.'\n        },\n        {\n            question: '¿Ofrecen soluciones de domótica?',\n            answer: 'Sí, integramos seguridad con control de accesos, iluminación, alarmas y climatización inteligente.'\n        },\n        {\n            question: '¿Cómo garantizan la privacidad de los datos?',\n            answer: 'Cumplimos la Ley de Protección de Datos y empleamos protocolos de ciberseguridad de nivel empresarial.'\n        }\n    ],\n    'Empresa y Operación': [\n        {\n            question: '¿Dónde opera Gard Security?',\n            answer: 'Ofrecemos cobertura a nivel nacional, con foco en grandes ciudades e industrias estratégicas.'\n        },\n        {\n            question: '¿Cuál es el proceso para contratar sus servicios?',\n            answer: 'Agendamos una reunión, realizamos un informe de vulnerabilidad, diseñamos un plan y firmamos contrato.'\n        },\n        {\n            question: '¿En cuánto tiempo puedo tener guardias operando?',\n            answer: 'Dependiendo del tipo de servicio, desde 24 horas hasta 5 días hábiles.'\n        },\n        {\n            question: '¿Qué los diferencia de otras empresas de seguridad privada?',\n            answer: 'Nuestro enfoque tecnológico, la personalización del servicio y un equipo humano altamente capacitado.'\n        },\n        {\n            question: '¿Cómo puedo cotizar un servicio?',\n            answer: 'Puedes llenar el formulario online, escribirnos por WhatsApp o llamarnos directamente. Respondemos en menos de 12 horas.'\n        }\n    ]\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./app/data/faqData.ts\n");

